utils_js = """// Simple 2D vector utility usable as a global "Vec"
(function(global){
  class Vec {
    constructor(x=0,y=0){ this.x = x; this.y = y; }
    copy(){ return new Vec(this.x,this.y); }
    add(v){ this.x += v.x; this.y += v.y; return this; }
    sub(v){ this.x -= v.x; this.y -= v.y; return this; }
    mul(s){ this.x *= s; this.y *= s; return this; }
    div(s){ if(s!==0){ this.x /= s; this.y /= s; } return this; }
    mag(){ return Math.hypot(this.x, this.y); }
    setMag(m){ const d = this.mag() || 1; this.mul(m / d); return this; }
    normalize(){ const m = this.mag() || 1; this.div(m); return this; }
    limit(max){ if(this.mag() > max) this.setMag(max); return this; }
    dist(v){ return Math.hypot(this.x - v.x, this.y - v.y); }
    static sub(a,b){ return new Vec(a.x - b.x, a.y - b.y); }
    static add(a,b){ return new Vec(a.x + b.x, a.y + b.y); }
  }
  global.Vec = Vec;
})(window);
"""

boid_js = """// Boid class, uses global Vec
(function(global){
  const Vec = global.Vec;

  class Boid {
    constructor(x,y, w,h){
      this.pos = new Vec(x,y);
      const angle = Math.random() * Math.PI * 2;
      this.vel = new Vec(Math.cos(angle), Math.sin(angle));
      this.acc = new Vec();
      this.maxForce = 0.05;
      this.maxSpeed = 2.5;
      this.size = 3 + Math.random()*3;
      this.hue = Math.floor(Math.random()*360);
      // bounds for wrapping
      this._w = w;
      this._h = h;
    }

    edges(){
      if(this.pos.x < -10) this.pos.x = this._w + 10;
      if(this.pos.x > this._w + 10) this.pos.x = -10;
      if(this.pos.y < -10) this.pos.y = this._h + 10;
      if(this.pos.y > this._h + 10) this.pos.y = -10;
    }

    align(boids, perception){
      const steering = new Vec();
      let total = 0;
      for(const other of boids){
        const d = this.pos.dist(other.pos);
        if(other !== this && d < perception){
          steering.add(other.vel);
          total++;
        }
      }
      if(total > 0){
        steering.div(total);
        steering.setMag(this.maxSpeed);
        steering.sub(this.vel);
        steering.limit(this.maxForce);
      }
      return steering;
    }

    cohesion(boids, perception){
      const steering = new Vec();
      let total = 0;
      for(const other of boids){
        const d = this.pos.dist(other.pos);
        if(other !== this && d < perception){
          steering.add(other.pos);
          total++;
        }
      }
      if(total > 0){
        steering.div(total);
        steering.sub(this.pos);
        steering.setMag(this.maxSpeed);
        steering.sub(this.vel);
        steering.limit(this.maxForce);
      }
      return steering;
    }

    separation(boids, perception){
      const steering = new Vec();
      let total = 0;
      for(const other of boids){
        const d = this.pos.dist(other.pos);
        if(other !== this && d < perception/1.5){
          const diff = Vec.sub(this.pos, other.pos);
          if(d>0) diff.div(d);
          steering.add(diff);
          total++;
        }
      }
      if(total > 0){
        steering.div(total);
        steering.setMag(this.maxSpeed);
        steering.sub(this.vel);
        steering.limit(this.maxForce * 1.5);
      }
      return steering;
    }

    applyBehaviors(boids, params){
      const align = this.align(boids, params.perception).mul(params.alignWeight);
      const coh = this.cohesion(boids, params.perception).mul(params.cohesionWeight);
      const sep = this.separation(boids, params.perception).mul(params.separationWeight);
      this.acc.add(align).add(coh).add(sep);
    }

    update(speedMultiplier){
      this.vel.add(this.acc);
      this.vel.limit(this.maxSpeed * speedMultiplier);
      this.pos.add(this.vel);
      this.acc.mul(0);
    }

    draw(ctx, showDebug=false){
      const angle = Math.atan2(this.vel.y, this.vel.x);
      ctx.save();
      ctx.translate(this.pos.x, this.pos.y);
      ctx.rotate(angle);
      // color varies with speed for a "colorful" effect
      const speed = this.vel.mag();
      const light = Math.min(70, 20 + speed * 20);
      ctx.fillStyle = `hsl(${this.hue} 80% ${light}%)`;
      ctx.beginPath();
      ctx.moveTo(this.size * 2, 0);
      ctx.lineTo(-this.size, this.size);
      ctx.lineTo(-this.size, -this.size);
      ctx.closePath();
      ctx.fill();
      if(showDebug){
        ctx.strokeStyle = 'rgba(255,255,255,0.08)';
        ctx.beginPath();
        ctx.arc(0,0,10,0,Math.PI*2);
        ctx.stroke();
      }
      ctx.restore();
    }
  }

  global.Boid = Boid;
})(window);
"""

main_js = """// Main simulation script. Assumes Vec and Boid are on window.
(function(global){
  const canvas = document.getElementById('flock');
  const ctx = canvas.getContext('2d', { alpha: true });
  const boids = [];
  let w = canvas.width = innerWidth;
  let h = canvas.height = innerHeight;

  const params = {
    count: 300,
    speed: 2.5,
    perception: 50,
    alignWeight: 1.0,
    cohesionWeight: 0.8,
    separationWeight: 1.6
  };

  // UI elements
  const countEl = document.getElementById('count');
  const speedEl = document.getElementById('speed');
  const perceptionEl = document.getElementById('perception');
  const pauseBtn = document.getElementById('pause');
  const info = document.getElementById('info');

  let running = true;
  let lastTime = performance.now();
  let fps = 0;
  let frameCount = 0;
  let fpsTime = 0;

  function resize(){
    w = canvas.width = innerWidth;
    h = canvas.height = innerHeight;
    for(const b of boids){ b._w = w; b._h = h; }
  }
  addEventListener('resize', resize);

  function createBoids(n){
    boids.length = 0;
    for(let i=0;i<n;i++){
      const x = Math.random()*w;
      const y = Math.random()*h;
      boids.push(new Boid(x,y,w,h));
    }
  }

  // controls
  countEl.addEventListener('input', (e)=>{
    params.count = +e.target.value;
    updateCount();
  });
  speedEl.addEventListener('input', (e)=>{
    params.speed = +e.target.value;
  });
  perceptionEl.addEventListener('input', (e)=>{
    params.perception = +e.target.value;
  });
  pauseBtn.addEventListener('click', ()=>{
    running = !running;
    pauseBtn.textContent = running ? 'Pause' : 'Resume';
    if(running) lastTime = performance.now();
  });

  canvas.addEventListener('click', (ev)=>{
    // add a few boids where clicked
    const rect = canvas.getBoundingClientRect();
    const x = ev.clientX - rect.left;
    const y = ev.clientY - rect.top;
    for(let i=0;i<6;i++){
      boids.push(new Boid(x + (Math.random()-0.5)*20, y + (Math.random()-0.5)*20, w,h));
    }
    // trim to max
    if(boids.length > 1200) boids.splice(0, boids.length - 1200);
  });

  function updateCount(){
    const diff = params.count - boids.length;
    if(diff > 0){
      for(let i=0;i<diff;i++){
        boids.push(new Boid(Math.random()*w, Math.random()*h, w,h));
      }
    }else if(diff < 0){
      boids.splice(diff);
    }
  }

  function step(ts){
    const dt = (ts - lastTime) / 16.666; // relative to 60fps
    lastTime = ts;
    if(!running){
      requestAnimationFrame(step);
      return;
    }

    // FPS calc
    frameCount++;
    fpsTime += (performance.now() - (fpsTime?0:0));
    if(frameCount % 10 === 0){
      fps = Math.round(1000 / (performance.now() - lastTime + 0.0001));
    }

    // clear with slight alpha for trails
    ctx.fillStyle = 'rgba(4,6,12,0.25)';
    ctx.fillRect(0,0,w,h);

    // update & draw boids
    const localBoids = boids; // alias
    for(const b of localBoids){
      b.applyBehaviors(localBoids, params);
      b.update(params.speed * dt);
      b.edges();
      b.draw(ctx);
    }

    // UI update
    info.textContent = `Boids: ${boids.length} | FPS: ${Math.round(1000/(performance.now()-lastTime||1))}`;
    requestAnimationFrame(step);
  }

  // initial setup
  createBoids(params.count);
  // slight delay for first frame accuracy
  requestAnimationFrame((t)=>{ lastTime = t; requestAnimationFrame(step); });

  // expose for debugging
  global.SIM = { boids, params, canvas, ctx, createBoids, updateCount };
})(window);
"""

# Delegate one child per file. Each child's CONTEXT will be the file content text.
handles = [
    delegate("index_html", "Write file './output/boids-simulation/index.html'. Use write_file(path, CONTEXT.read()). CONTEXT is the full file text.", index_html),
    delegate("style_css", "Write file './output/boids-simulation/style.css'. Use write_file(path, CONTEXT.read()). CONTEXT is the full file text.", style_css),
    delegate("utils_js", "Write file './output/boids-simulation/src/utils.js'. Use write_file(path, CONTEXT.read()). CONTEXT is the full file text.", utils_js),
    delegate("boid_js",  "Write file './output/boids-simulation/src/boid.js'. Use write_file(path, CONTEXT.read()). CONTEXT is the full file text.", boid_js),
    delegate("main_js",  "Write file './output/boids-simulation/src/main.js'. Use write_file(path, CONTEXT.read()). CONTEXT is the full file text.", main_js),
]

# Wait for all children to finish writing files.
results = yield wait(*handles)
# results is a list of child return values (strings). Continue below to verify files.

# Verification: ensure files exist and contain expected signatures.
paths = [
  "./output/boids-simulation/index.html",
  "./output/boids-simulation/style.css",
  "./output/boids-simulation/src/utils.js",
  "./output/boids-simulation/src/boid.js",
  "./output/boids-simulation/src/main.js",
]

# Read files and run simple assertions
for p in paths:
  content = read_file(p)
  assert len(content) > 20, f"File {p} seems too small."

# Specific content checks
idx = read_file(paths[0])
assert "<canvas" in idx and "src=\"src/utils.js\"" in idx and "src=\"src/boid.js\"" in idx and "src=\"src/main.js\"" in idx, "index.html missing expected tags or script links."

css = read_file(paths[1])
assert "canvas" in css and "background" in css, "style.css seems incomplete."

utils = read_file(paths[2])
assert "class Vec" in utils and "global.Vec" in utils, "utils.js missing Vec definition."

boid = read_file(paths[3])
assert "class Boid" in boid and "applyBehaviors" in boid and "draw(ctx" in boid, "boid.js missing expected methods."

main = read_file(paths[4])
assert "requestAnimationFrame" in main and "createBoids" in main and "params" in main, "main.js missing expected bits."

# Final message with instructions
done("Wrote boids simulation to ./output/boids-simulation/ — files: index.html, style.css, src/utils.js, src/boid.js, src/main.js. Open ./output/boids-simulation/index.html in a browser to run the simulation. (If your browser blocks module-less file imports when opened via file://, serve the folder with a simple static server.)")
